@using sv_623387d0eda94d80a4af994eb39297e1.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-container d-flex">
    @* ── Left Sidebar ── *@
    <aside class="catalog-sidebar p-3 border-end">
        <h5>Filters</h5>

        @* Category checkboxes *@
        <div class="mb-3">
            <label class="form-label fw-semibold">Category</label>
            @if (_categories is not null)
            {
                @foreach (var cat in _categories)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                               checked="@_selectedCategories.Contains(cat)"
                               @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                        <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                    </div>
                }
            }
        </div>

        @* Price range *@
        <div class="mb-3">
            <label class="form-label fw-semibold">Price Range</label>
            <div class="d-flex gap-2">
                <input type="number" class="form-control" placeholder="Min"
                       @bind="_minPrice" @bind:event="oninput" min="0" />
                <input type="number" class="form-control" placeholder="Max"
                       @bind="_maxPrice" @bind:event="oninput" min="0" />
            </div>
        </div>

        @* In stock toggle *@
        <div class="form-check mb-3">
            <input class="form-check-input" type="checkbox" id="inStockOnly"
                   @bind="_inStockOnly" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>

        <div class="d-grid gap-2">
            <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    @* ── Main Content ── *@
    <main class="catalog-main flex-grow-1 p-3">
        @if (_error is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_error
            </div>
        }
        else if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="alert alert-info text-center" role="alert">
                No products found. Try adjusting your filters.
            </div>
        }
        else
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label me-2 mb-0">Sort by:</label>
                    <select class="form-select d-inline-block w-auto" @onchange="OnSortChanged">
                        @foreach (var opt in _sortOptions)
                        {
                            <option value="@opt.Value" selected="@(opt.Value == _sortBy)">@opt.Label</option>
                        }
                    </select>
                </div>
                <span class="text-muted">
                    Showing @((_result.Page - 1) * _result.PageSize + 1)–@(Math.Min(_result.Page * _result.PageSize, _result.TotalCount))
                    of @_result.TotalCount products
                </span>
            </div>

            @* Product grid *@
            <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
                @foreach (var product in _result.Items)
                {
                    <div class="col">
                        <ProductCard Product="product"
                                     OnProductSelected="OnProductSelected"
                                     OnAddToCart="OnAddToCart" />
                    </div>
                }
            </div>

            @* Pagination *@
            <nav class="mt-4" aria-label="Product pagination">
                <ul class="pagination justify-content-center">
                    <li class="page-item @(_currentPage <= 1 ? "disabled" : "")">
                        <button class="page-link" @onclick="() => GoToPage(_currentPage - 1)"
                                disabled="@(_currentPage <= 1)">Previous</button>
                    </li>
                    @for (int i = 1; i <= _totalPages; i++)
                    {
                        var pageNum = i;
                        <li class="page-item @(pageNum == _currentPage ? "active" : "")">
                            <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                        </li>
                    }
                    <li class="page-item @(_currentPage >= _totalPages ? "disabled" : "")">
                        <button class="page-link" @onclick="() => GoToPage(_currentPage + 1)"
                                disabled="@(_currentPage >= _totalPages)">Next</button>
                    </li>
                </ul>
            </nav>
        }
    </main>
</div>

@code {
    private const int PageSize = 12;

    private List<string>? _categories;
    private readonly HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;

    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    private int _totalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    private static readonly (string Value, string Label)[] _sortOptions =
    [
        ("price_asc", "Price: Low to High"),
        ("price_desc", "Price: High to Low"),
        ("name_asc", "Name: A-Z"),
        ("rating_desc", "Rating: Highest"),
    ];

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProducts();
            _categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task SearchProducts()
    {
        _loading = true;
        _error = null;

        try
        {
            var filter = new ProductFilter(
                _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
                _minPrice,
                _maxPrice,
                _inStockOnly
            );

            _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        _currentPage = 1;
        await SearchProducts();
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await SearchProducts();
    }

    private async Task OnSortChanged(ChangeEventArgs e)
    {
        _sortBy = e.Value?.ToString() ?? "price_asc";
        _currentPage = 1;
        await SearchProducts();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > _totalPages) return;
        _currentPage = page;
        await SearchProducts();
    }

    private void OnProductSelected(Product product)
    {
        // Parent layout or NavigationManager can handle navigation to detail page
    }

    private void OnAddToCart(Product product)
    {
        // Cart logic handled upstream
    }
}
"}

